import threading
import functools

def debounce(wait_time):
    def decorator(func):
        _timer = None
        _last_args = None
        _last_kwargs = None
        _lock = threading.Lock()

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            nonlocal _timer, _last_args, _last_kwargs

            def call_it():
                with _lock:
                    if _last_args is not None:
                        func(*_last_args, **_last_kwargs)

            with _lock:
                if _timer is not None:
                    _timer.cancel()

                _last_args = args
                _last_kwargs = kwargs

                _timer = threading.Timer(wait_time, call_it)
                _timer.start()

        return wrapper
    return decorator
